  AcademicCapIcon,
  UserGroupIcon,
  DocumentTextIcon,
  CalendarIcon,
  ChartBarIcon,
  ClockIcon,
  CheckCircleIcon,
  ExclamationCircleIcon,
  EyeIcon,
  XIcon,
  TrendingUpIcon,
  HeartIcon,
  ChatIcon,
  ShareIcon,
  OfficeBuildingIcon,
  LocationMarkerIcon
} from '@heroicons/react/outline';
import toast from 'react-hot-toast';

const AlumniDashboard = () => {
  const navigate = useNavigate();
  const [stats, setStats] = useState({
    totalConnections: 0,
    mentorshipRequests: 0,
    jobApplications: 0,
    eventsAttended: 0
  });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const userData = localStorage.getItem('user');
    const token = localStorage.getItem('token');

    if (userData && token) {
      try {
        const parsedUser = JSON.parse(userData);

        if (parsedUser.role !== 'alumni') {
          navigate('/login');
          return;
        }
      } catch (error) {
        console.error('Error parsing user data:', error);
        navigate('/login');
        return;
      }
    } else {
      navigate('/login');
      return;
    }

    fetchDashboardData();
  }, []);

  const fetchDashboardData = async () => {
    try {
      setLoading(true);

      // Fetch user's connections
      const connectionsResponse = await fetch('/api/connections/my-connections');
      const connectionsData = await connectionsResponse.json();

      // Fetch mentorship requests
      const mentorshipResponse = await fetch('/api/mentorship/my-requests');
      const mentorshipData = await mentorshipResponse.json();

      // Fetch job applications
      const applicationsResponse = await fetch('/api/jobs/my-applications');
      const applicationsData = await applicationsResponse.json();

      // Fetch events attended
      const eventsResponse = await fetch('/api/events/my-events');
      const eventsData = await eventsResponse.json();

      if (connectionsResponse.ok && connectionsData.success) {
        setStats(prev => ({
          ...prev,
          totalConnections: connectionsData.data?.length || 0
        }));
      }

      if (mentorshipResponse.ok && mentorshipData.success) {
        setStats(prev => ({
          ...prev,
          mentorshipRequests: mentorshipData.data?.length || 0
        }));
      }

      if (applicationsResponse.ok && applicationsData.success) {
        setStats(prev => ({
          ...prev,
          jobApplications: applicationsData.data?.length || 0
        }));
      }

      if (eventsResponse.ok && eventsData.success) {
        setStats(prev => ({
          ...prev,
          eventsAttended: eventsData.data?.length || 0
        }));
      }

    } catch (error) {
      console.error('Error fetching dashboard data:', error);
      toast.error('Failed to load dashboard data');
    } finally {
      setLoading(false);
    }
  };

  const renderOverview = () => (
    <div className="space-y-6">
      {/* Stats Cards Grid */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-gradient-to-br from-blue-500 to-blue-600 rounded-xl shadow-lg p-6 text-white hover:shadow-xl transition-all duration-300 transform hover:scale-105">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-3xl font-bold">{stats.totalConnections}</p>
              <p className="text-blue-100">Connections</p>
            </div>
            <div className="p-3 bg-white/20 rounded-full">
              <UserGroupIcon className="h-8 w-8 text-white" />
            </div>
          </div>
          <div className="mt-4 flex items-center text-sm text-blue-100">
            <TrendingUpIcon className="h-4 w-4 mr-1" />
            <span>+12% this month</span>
          </div>
        </div>

        <div className="bg-gradient-to-br from-green-500 to-green-600 rounded-xl shadow-lg p-6 text-white hover:shadow-xl transition-all duration-300 transform hover:scale-105">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-3xl font-bold">{stats.mentorshipRequests}</p>
              <p className="text-green-100">Mentorship</p>
            </div>
            <div className="p-3 bg-white/20 rounded-full">
              <BriefcaseIcon className="h-8 w-8 text-white" />
            </div>
          </div>
          <div className="mt-4 flex items-center text-sm text-green-100">
            <TrendingUpIcon className="h-4 w-4 mr-1" />
            <span>+5% this month</span>
          </div>
        </div>

        <div className="bg-gradient-to-br from-purple-500 to-purple-600 rounded-xl shadow-lg p-6 text-white hover:shadow-xl transition-all duration-300 transform hover:scale-105">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-3xl font-bold">{stats.jobApplications}</p>
              <p className="text-purple-100">Applications</p>
            </div>
            <div className="p-3 bg-white/20 rounded-full">
              <DocumentTextIcon className="h-8 w-8 text-white" />
            </div>
          </div>
          <div className="mt-4 flex items-center text-sm text-purple-100">
            <TrendingUpIcon className="h-4 w-4 mr-1" />
            <span>+8% this month</span>
          </div>
        </div>

        <div className="bg-gradient-to-br from-orange-500 to-orange-600 rounded-xl shadow-lg p-6 text-white hover:shadow-xl transition-all duration-300 transform hover:scale-105">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-3xl font-bold">{stats.eventsAttended}</p>
              <p className="text-orange-100">Events</p>
            </div>
            <div className="p-3 bg-white/20 rounded-full">
              <CalendarIcon className="h-8 w-8 text-white" />
            </div>
          </div>
          <div className="mt-4 flex items-center text-sm text-orange-100">
            <TrendingUpIcon className="h-4 w-4 mr-1" />
            <span>+3% this month</span>
          </div>
        </div>
      </div>
    </div>
  );

  const renderQuickActions = () => (
    <div className="bg-white rounded-lg shadow-md p-6">
      <h3 className="text-lg font-semibold text-gray-900 mb-4">Quick Actions</h3>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <button
          onClick={() => navigate('/alumni-discovery')}
          className="flex items-center p-4 bg-mvsr-50 text-white rounded-lg hover:bg-mvsr-700 transition-colors"
        >
          <UsersIcon className="h-5 w-5 mr-2" />
          <span>Discover Alumni</span>
        </button>

        <button
          onClick={() => navigate('/alumni-profile/' + JSON.parse(localStorage.getItem('user')).id)}
          className="flex items-center p-4 bg-mvsr-50 text-white rounded-lg hover:bg-mvsr-700 transition-colors"
        >
          <UserGroupIcon className="h-5 w-5 mr-2" />
          <span>My Profile</span>
        </button>
      </div>
    </div>
  );

  const renderRecentActivity = () => (
    <div className="bg-white rounded-lg shadow-md p-6">
      <h3 className="text-lg font-semibold text-gray-900 mb-4">Recent Activity</h3>
      <div className="space-y-4">
        <div className="flex items-center p-4 bg-gray-50 rounded-lg">
          <div className="flex-shrink-0">
            <div className="w-10 h-10 bg-green-500 rounded-full flex items-center justify-center">
              <CheckCircleIcon className="h-6 w-6 text-white" />
            </div>
          </div>
          <div className="ml-4">
            <p className="text-sm font-medium text-gray-900">Profile Updated</p>
            <p className="text-xs text-gray-500">2 hours ago</p>
          </div>
        </div>

        <div className="flex items-center p-4 bg-gray-50 rounded-lg">
          <div className="flex-shrink-0">
            <div className="w-10 h-10 bg-blue-500 rounded-full flex items-center justify-center">
              <HeartIcon className="h-6 w-6 text-white" />
            </div>
          </div>
          <div className="ml-4">
            <p className="text-sm font-medium text-gray-900">New Connection</p>
            <p className="text-xs text-gray-500">1 day ago</p>
          </div>
        </div>
      </div>
    </div>
  );

  if (loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-mvsr-600"></div>
        <span className="ml-3 text-gray-600">Loading dashboard...</span>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50 py-8">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="bg-white rounded-lg shadow-md p-6 mb-8">
          <div className="flex items-center justify-between">
            <div>
              <h1 className="text-3xl font-bold text-gray-900">Alumni Dashboard</h1>
              <p className="text-gray-600">Welcome back! Here's your alumni overview</p>
            </div>
            <div className="flex items-center space-x-4">
              <button
                onClick={() => navigate('/alumni-discovery')}
                className="px-4 py-2 bg-gray-200 text-gray-700 rounded-lg hover:bg-gray-300 transition-colors"
              >
                Alumni Discovery
              </button>
              <button
                onClick={() => {
                  localStorage.removeItem('user');
                  localStorage.removeItem('token');
                  navigate('/login');
                }}
                className="px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 transition-colors"
              >
                Logout
              </button>
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {renderOverview()}
          {renderQuickActions()}
          {renderRecentActivity()}
        </div>
      </div>
    </div>
  );
};

export default AlumniDashboard;
